import{_ as r,c as o,o as s,ag as n}from"./chunks/framework.XjE0kKti.js";const a="/gatewayweb/docs/assets/hub0043-config-list.Byt4e5pN.png",d="/gatewayweb/docs/assets/hub0043-config-context.CS2MmdJ6.png",e="/gatewayweb/docs/assets/hub0043-config-form.8llz5K_O.png",g="/gatewayweb/docs/assets/hub0043-config-rollback.DEoJBA7e.png",f=JSON.parse('{"title":"配置中心（hub0043）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0043.md","filePath":"modules/hub0043.md","lastUpdated":null}'),h={name:"modules/hub0043.md"};function l(i,t,b,c,u,p){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="配置中心-hub0043" tabindex="-1">配置中心（hub0043） <a class="header-anchor" href="#配置中心-hub0043" aria-label="Permalink to &quot;配置中心（hub0043）&quot;">​</a></h1><p>在选定 <strong>命名空间</strong> 下集中管理配置项（Data ID / 分组 / 内容类型 / 版本与 MD5），支持新建、编辑、删除、查看详情，并可在 <strong>配置历史</strong> 中审计变更、查看单次修改详情及执行 <strong>回滚</strong>。本模块与 <strong><a href="./hub0041.html">命名空间管理（hub0041）</a></strong> 配合使用：搜索区「命名空间」通过选择器绑定 <code>namespaceId</code>。</p><p><img src="'+a+'" alt="配置列表与筛选"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>配置列表</td><td>按命名空间（必填）、分组、配置 ID、内容类型筛选并分页展示。</td></tr><tr><td>新建 / 编辑 / 查看</td><td>使用<strong>全页表单视图</strong>（非弹窗）：从列表进入，编辑完成后 <strong>发布</strong> 或 <strong>保存</strong>，通过 <strong>返回列表</strong> 回到表格。</td></tr><tr><td>删除</td><td>支持当前行或勾选批量删除，均有确认提示。</td></tr><tr><td>历史与回滚</td><td>从列表右键进入历史页；历史列表支持查看详情、回滚到指定版本（会再经二次确认）。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>服务治理</strong> → <strong>配置中心</strong>。</p><p>同一页面内在 <strong>配置列表</strong> 与 <strong>配置历史</strong> 两个视图间切换（由列表右键「历史版本」进入历史，历史中 <strong>返回配置列表</strong> 回到列表）。</p><hr><h2 id="配置列表" tabindex="-1">配置列表 <a class="header-anchor" href="#配置列表" aria-label="Permalink to &quot;配置列表&quot;">​</a></h2><h3 id="命名空间为必填" tabindex="-1">命名空间为必填 <a class="header-anchor" href="#命名空间为必填" aria-label="Permalink to &quot;命名空间为必填&quot;">​</a></h3><p>搜索表单中 <strong>命名空间</strong> 为必填项（带校验）。未选择命名空间时点击 <strong>查询</strong>，会提示「请先选择命名空间」，且不会加载列表。<strong>新建配置</strong>、<strong>编辑</strong>、<strong>删除</strong> 在点击前同样会校验是否已选择命名空间。</p><p>命名空间通过「…」打开 <strong><a href="./hub0041.html">hub0041</a></strong> 中的命名空间选择器进行选择。</p><h3 id="其它筛选项" tabindex="-1">其它筛选项 <a class="header-anchor" href="#其它筛选项" aria-label="Permalink to &quot;其它筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>分组名称</strong></td><td>可选；占位：请输入分组名称，为空时查询全部。</td></tr><tr><td><strong>配置 ID</strong></td><td>可选；支持模糊查询。</td></tr><tr><td><strong>内容类型</strong></td><td>全部 / 文本 / JSON / XML / YAML / Properties。</td></tr></tbody></table><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新建配置</strong></td><td>进入表单视图新增；若列表搜索区已选命名空间，会带入表单中的 <strong>命名空间 ID</strong>（表单内为只读选择器）。</td></tr><tr><td><strong>编辑</strong></td><td>优先使用表格 <strong>当前单击行</strong>；若无当前行，则使用 <strong>勾选且仅一条</strong> 记录。未选中时提示先选择。</td></tr><tr><td><strong>删除</strong></td><td>若有 <strong>当前单击行</strong>，则对该行发起删除确认；否则按 <strong>勾选的多行</strong> 批量删除（确认框中列出配置 ID）。</td></tr><tr><td><strong>查询 / 重置</strong></td><td>刷新列表或重置筛选（仍需命名空间才能查出数据）。</td></tr></tbody></table><h3 id="表格列" tabindex="-1">表格列 <a class="header-anchor" href="#表格列" aria-label="Permalink to &quot;表格列&quot;">​</a></h3><p>常见列包括：<strong>配置 ID</strong>、<strong>命名空间</strong>、<strong>分组名称</strong>、<strong>内容类型</strong>（界面展示为中文，如 Properties）、<strong>描述</strong>、<strong>版本</strong>、<strong>MD5</strong>、<strong>创建时间</strong>、<strong>创建人</strong> 等。MD5 用于比对配置内容是否变化。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p><img src="'+d+'" alt="配置列表右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据 / 复制单元格</strong></td><td>表格通用能力。</td></tr><tr><td><strong>查看详情</strong></td><td>进入表单视图，模式为只读，无底部提交按钮。</td></tr><tr><td><strong>编辑</strong></td><td>拉取详情后进入可编辑表单视图。</td></tr><tr><td><strong>历史版本</strong></td><td>切换到 <strong>配置历史</strong> 子视图，并自动带上当前行的命名空间、分组、配置 ID，默认 <strong>限制数量</strong> 为 50 且自动查询。</td></tr><tr><td><strong>删除</strong></td><td>删除当前行对应配置（单独确认框）。</td></tr></tbody></table><hr><h2 id="新建-编辑-查看-表单视图" tabindex="-1">新建 / 编辑 / 查看（表单视图） <a class="header-anchor" href="#新建-编辑-查看-表单视图" aria-label="Permalink to &quot;新建 / 编辑 / 查看（表单视图）&quot;">​</a></h2><p>列表与表单通过 <strong>返回列表</strong> 切换。提交按钮文案：<strong>新增</strong> 为 <strong>发布</strong>，<strong>编辑</strong> 为 <strong>保存</strong>；查看模式不显示提交按钮。</p><p><img src="'+e+'" alt="配置表单（示例为 Properties）"></p><h3 id="主要字段" tabindex="-1">主要字段 <a class="header-anchor" href="#主要字段" aria-label="Permalink to &quot;主要字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>命名空间 ID</strong></td><td>必填；表单内为只读选择器，通常来自列表页已选命名空间。</td></tr><tr><td><strong>分组名称</strong></td><td>默认常见为 <code>DEFAULT_GROUP</code>，可按业务修改（以环境约定为准）。</td></tr><tr><td><strong>配置数据 ID</strong></td><td>必填，即配置主键（如 <code>xxx.properties</code>）。</td></tr><tr><td><strong>配置描述</strong></td><td>可选。</td></tr><tr><td><strong>变更原因</strong></td><td>可选；建议重大变更时填写，便于历史审计。</td></tr><tr><td><strong>版本号 / MD5 值</strong></td><td>只读，由系统在发布或保存后维护。</td></tr><tr><td><strong>内容类型</strong></td><td>单选：文本、JSON、XML、YAML、Properties；会切换下方编辑器的语言高亮与校验模式。</td></tr><tr><td><strong>配置内容</strong></td><td>必填；使用代码编辑器（高度约 400px），请保证内容与所选 <strong>内容类型</strong> 一致，避免解析失败。</td></tr></tbody></table><hr><h2 id="配置历史与回滚" tabindex="-1">配置历史与回滚 <a class="header-anchor" href="#配置历史与回滚" aria-label="Permalink to &quot;配置历史与回滚&quot;">​</a></h2><p>从配置列表右键 <strong>历史版本</strong> 进入后，顶部工具栏包含 <strong>返回配置列表</strong>（回到主列表视图）。</p><h3 id="历史列表筛选" tabindex="-1">历史列表筛选 <a class="header-anchor" href="#历史列表筛选" aria-label="Permalink to &quot;历史列表筛选&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>命名空间</strong></td><td>必填。</td></tr><tr><td><strong>分组名称</strong></td><td>必填（从列表带入时常为 <code>DEFAULT_GROUP</code>）。</td></tr><tr><td><strong>配置 ID</strong></td><td>必填。</td></tr><tr><td><strong>限制数量</strong></td><td>默认 50，用于限制拉取的历史条数。</td></tr></tbody></table><p>使用 <strong>查询 / 重置</strong> 刷新历史表。历史表 <strong>不分页</strong>。</p><h3 id="历史表列与右键" tabindex="-1">历史表列与右键 <a class="header-anchor" href="#历史表列与右键" aria-label="Permalink to &quot;历史表列与右键&quot;">​</a></h3><p>表格展示 <strong>历史 ID</strong>、命名空间、分组、配置 ID、<strong>变更类型</strong>（创建 / 更新 / 删除 / 回滚 等标签）、<strong>旧版本 / 新版本</strong>、<strong>旧 MD5 / 新 MD5</strong>、变更原因、变更人、变更时间等。</p><p>右键菜单：</p><ul><li><strong>查看详情</strong>：进入只读详情视图（含基本信息与历史中的配置内容 Tab），顶部 <strong>返回列表</strong> 回到历史表。</li><li><strong>回滚</strong>：打开 <strong>配置回滚</strong> 对话框。</li></ul><h3 id="配置回滚对话框" tabindex="-1">配置回滚对话框 <a class="header-anchor" href="#配置回滚对话框" aria-label="Permalink to &quot;配置回滚对话框&quot;">​</a></h3><p><img src="'+g+'" alt="配置回滚"></p><ul><li><strong>目标版本</strong>：只读展示，来自所选历史记录中的新版本号（即要回滚到的目标版本语义，以后端为准）。</li><li><strong>变更原因</strong>：可选。<br> 点击 <strong>确定</strong> 后，还会弹出 <strong>二次确认</strong>（提示将创建新的配置版本等），确认后执行回滚并刷新历史列表。</li></ul><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>先在 <strong><a href="./hub0041.html">命名空间管理（hub0041）</a></strong> 创建命名空间，再在本页选择该空间维护配置。</li><li>修改生产配置前建议使用 <strong>历史版本</strong> 确认当前版本与 MD5，必要时先 <strong>查看详情</strong> 备份内容。</li><li><strong>内容类型</strong> 与实际文本不一致时，可能导致客户端或服务端解析失败，发布前请自检语法。</li><li>回滚会产生新版本链路，请在变更原因中写清业务背景，便于排障。</li></ol>',46)])])}const q=r(h,[["render",l]]);export{f as __pageData,q as default};
